import { useState, useEffect } from 'react';
import axiosInstance from '../axiosConfig';
import TourForm from '../components/TourForm';
import TourList from '../components/TourList';
import { useAuth } from '../context/AuthContext';

const Tours = () => {
  const { user } = useAuth();
  const [tours, setTours] = useState([]);
  const [editingTour, setEditingTour] = useState(null);
  const [showForm, setShowForm] = useState(false);

  const fetchTours = async () => {
    try {
      const response = await axiosInstance.get('/api/tours', {
        headers: { Authorization: `Bearer ${user?.token}` },
      });
      setTours(response.data);
    } catch (error) {
      console.error('抓取行程失敗:', error);
    }
  };

  useEffect(() => {
    if (user) fetchTours();
  }, [user]);

  // 重點修改：點擊列表項目觸發
  const handleSelectTour = (tour) => {
    setEditingTour(tour); // 將選中的行程傳給表單進行「編輯」
    setShowForm(true);    // 開啟全螢幕表單/詳情頁
  };

  const handleSuccess = () => {
    setShowForm(false);
    setEditingTour(null);
    fetchTours(); 
  };

  return (
    <div className="bg-gray-100 min-h-screen">
      <div className="max-w-[420px] mx-auto bg-white min-h-screen shadow-2xl relative overflow-hidden flex flex-col">

        {/* Header */}
        <div className="flex justify-between items-center p-5 border-b bg-white sticky top-0 z-10">
          <h1 className="text-xl font-black text-gray-900">Inventory</h1>
          <button 
            onClick={() => { setEditingTour(null); setShowForm(true); }}
            className="text-emerald-500 font-bold hover:text-emerald-600 transition"
          >
            + New
          </button>
        </div>

        {/* 內容區 */}
        <div className="flex-1 overflow-y-auto p-4 bg-gray-50">
          <div className="flex justify-between items-end mb-4 px-1">
            <h2 className="text-lg font-bold text-gray-800">Order List</h2>
            <span className="text-xs text-gray-400 font-medium">{tours.length} items</span>
          </div>

          {/* 修正：點擊整條 Item 或 Edit 都能進入編輯 */}
          <TourList 
            tours={tours} 
            setTours={setTours} 
            setEditingTour={handleSelectTour} 
          />
        </div>

        {/* 彈出式表單：這就是你截圖中的詳情/編輯頁面 */}
        {showForm && (
          <div className="fixed inset-0 z-50 flex justify-center bg-black bg-opacity-40 backdrop-blur-sm">
            <div className="w-full max-w-[420px] bg-white h-full overflow-y-auto animate-slide-up">
              <TourForm
                tours={tours}
                setTours={setTours}
                editingTour={editingTour} // 如果有值，表單會顯示「編輯」；沒值則是「新增」
                onClose={() => { setShowForm(false); setEditingTour(null); }}
                onSuccess={handleSuccess}
              />
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Tours;
